-- Auto-generated by pg_pack (purchase, purchase_ut, purchase_qa)
-- 2026-03-12

-- Schema: purchase
CREATE SCHEMA IF NOT EXISTS purchase;

CREATE OR REPLACE FUNCTION purchase._fournisseur_options()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_html text := '<option value="">-- Choisir un fournisseur --</option>';
  r record;
BEGIN
  FOR r IN SELECT id, name FROM crm.client WHERE active ORDER BY name LOOP
    v_html := v_html || format('<option value="%s">%s</option>', r.id, pgv.esc(r.name));
  END LOOP;
  RETURN v_html;
END;
$function$;
COMMENT ON FUNCTION purchase._fournisseur_options() IS 'HTML select options for CRM clients as suppliers';

CREATE OR REPLACE FUNCTION purchase._next_numero(p_prefix text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_year text := to_char(now(), 'YYYY');
  v_seq int;
BEGIN
  SELECT coalesce(max(
    regexp_replace(numero, '^.*-(\d+)$', '\1')::int
  ), 0) + 1
  INTO v_seq
  FROM purchase.commande
  WHERE numero LIKE p_prefix || '-' || v_year || '-%'
  UNION ALL
  SELECT coalesce(max(
    regexp_replace(numero, '^.*-(\d+)$', '\1')::int
  ), 0) + 1
  FROM purchase.reception
  WHERE numero LIKE p_prefix || '-' || v_year || '-%'
  ORDER BY 1 DESC LIMIT 1;

  RETURN p_prefix || '-' || v_year || '-' || lpad(v_seq::text, 3, '0');
END;
$function$;
COMMENT ON FUNCTION purchase._next_numero(text) IS 'Generate next sequential number (CMD-2026-001, REC-2026-001)';

CREATE OR REPLACE FUNCTION purchase._quantite_restante(p_ligne_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_commandee numeric;
  v_recue numeric;
BEGIN
  SELECT quantite INTO v_commandee FROM purchase.ligne WHERE id = p_ligne_id;
  SELECT coalesce(sum(quantite_recue), 0) INTO v_recue
    FROM purchase.reception_ligne WHERE ligne_id = p_ligne_id;
  RETURN v_commandee - v_recue;
END;
$function$;
COMMENT ON FUNCTION purchase._quantite_restante(integer) IS 'Remaining quantity to receive for an order line';

CREATE OR REPLACE FUNCTION purchase._set_updated_at()
 RETURNS trigger
 LANGUAGE plpgsql
AS $function$
BEGIN
  NEW.updated_at := now();
  RETURN NEW;
END;
$function$;
COMMENT ON FUNCTION purchase._set_updated_at() IS 'Trigger function to auto-update updated_at timestamp';

CREATE OR REPLACE FUNCTION purchase._statut_badge(p_statut text)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN CASE p_statut
    WHEN 'brouillon' THEN pgv.badge(p_statut, 'default')
    WHEN 'envoyee' THEN pgv.badge(p_statut, 'primary')
    WHEN 'partiellement_recue' THEN pgv.badge('partielle', 'warning')
    WHEN 'recue' THEN pgv.badge(p_statut, 'success')
    WHEN 'annulee' THEN pgv.badge(p_statut, 'danger')
    WHEN 'validee' THEN pgv.badge(p_statut, 'success')
    WHEN 'payee' THEN pgv.badge(p_statut, 'success')
    ELSE pgv.badge(p_statut, 'default')
  END;
END;
$function$;
COMMENT ON FUNCTION purchase._statut_badge(text) IS 'Colored status badge for purchase statuses';

CREATE OR REPLACE FUNCTION purchase._total_ht(p_commande_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN coalesce((
    SELECT sum(quantite * prix_unitaire)
    FROM purchase.ligne
    WHERE commande_id = p_commande_id
  ), 0);
END;
$function$;
COMMENT ON FUNCTION purchase._total_ht(integer) IS 'Total HT for a purchase order';

CREATE OR REPLACE FUNCTION purchase._total_tva(p_commande_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN coalesce((
    SELECT sum(quantite * prix_unitaire * tva_rate / 100)
    FROM purchase.ligne
    WHERE commande_id = p_commande_id
  ), 0);
END;
$function$;
COMMENT ON FUNCTION purchase._total_tva(integer) IS 'Total TVA for a purchase order';

CREATE OR REPLACE FUNCTION purchase._total_ttc(p_commande_id integer)
 RETURNS numeric
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN purchase._total_ht(p_commande_id) + purchase._total_tva(p_commande_id);
END;
$function$;
COMMENT ON FUNCTION purchase._total_ttc(integer) IS 'Total TTC for a purchase order';

CREATE OR REPLACE FUNCTION purchase.brand()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN 'Achats';
END;
$function$;
COMMENT ON FUNCTION purchase.brand() IS 'Brand name for purchase module';

CREATE OR REPLACE FUNCTION purchase.get_commande(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_fournisseur text;
  v_body text;
  v_rows text[];
  v_rows_r text[];
  r record;
BEGIN
  -- Liste si pas d'id
  IF p_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT c.id, c.fournisseur_id, c.numero, cl.name AS fournisseur, c.objet, c.statut,
             purchase._total_ttc(c.id) AS ttc, c.created_at
        FROM purchase.commande c
        JOIN crm.client cl ON cl.id = c.fournisseur_id
       ORDER BY c.created_at DESC
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_commande', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
        format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)),
        pgv.esc(r.objet),
        purchase._statut_badge(r.statut),
        to_char(r.ttc, 'FM999 990.00') || ' EUR',
        to_char(r.created_at, 'DD/MM/YYYY')
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      RETURN pgv.empty('Aucune commande', 'Créez votre première commande fournisseur.')
        || format('<p><a href="%s" role="button">Nouvelle commande</a></p>', pgv.call_ref('get_commande_form'));
    END IF;

    RETURN '<p>' || format('<a href="%s" role="button">Nouvelle commande</a>', pgv.call_ref('get_commande_form')) || '</p>'
      || pgv.md_table(ARRAY['Numéro', 'Fournisseur', 'Objet', 'Statut', 'Total TTC', 'Date'], v_rows);
  END IF;

  -- Détail
  SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
  SELECT name INTO v_fournisseur FROM crm.client WHERE id = v_cmd.fournisseur_id;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.card('Commande', v_cmd.numero || '<br>' || purchase._statut_badge(v_cmd.statut)),
    pgv.card('Fournisseur', format('<a href="/crm/client?p_id=%s">%s</a>', v_cmd.fournisseur_id, pgv.esc(v_fournisseur))),
    pgv.card('Total TTC', to_char(purchase._total_ttc(p_id), 'FM999 990.00') || ' EUR'),
    pgv.card('Livraison', coalesce(to_char(v_cmd.date_livraison, 'DD/MM/YYYY'), '—'))
  ]);

  IF v_cmd.objet <> '' THEN
    v_body := v_body || '<p><strong>Objet :</strong> ' || pgv.esc(v_cmd.objet) || '</p>';
  END IF;
  IF v_cmd.notes <> '' THEN
    v_body := v_body || '<p><strong>Notes :</strong> ' || pgv.esc(v_cmd.notes) || '</p>';
  END IF;

  -- Lignes
  v_rows := ARRAY[]::text[];
  FOR r IN
    SELECT l.id, l.description, l.quantite, l.unite, l.prix_unitaire, l.tva_rate,
           (l.quantite * l.prix_unitaire) AS total_ht,
           purchase._quantite_restante(l.id) AS restante
      FROM purchase.ligne l
     WHERE l.commande_id = p_id
     ORDER BY l.sort_order
  LOOP
    v_rows := v_rows || ARRAY[
      pgv.esc(r.description),
      r.quantite::text || ' ' || r.unite,
      to_char(r.prix_unitaire, 'FM999 990.00') || ' EUR',
      r.tva_rate::text || '%',
      to_char(r.total_ht, 'FM999 990.00') || ' EUR',
      CASE WHEN v_cmd.statut IN ('envoyee', 'partiellement_recue')
        THEN r.restante::text || ' ' || r.unite
        ELSE '—'
      END,
      CASE WHEN v_cmd.statut = 'brouillon'
        THEN pgv.action('post_ligne_supprimer', 'Supprimer',
               jsonb_build_object('p_ligne_id', r.id),
               'Supprimer cette ligne ?', 'danger')
        ELSE ''
      END
    ];
  END LOOP;

  v_body := v_body || '<h4>Lignes</h4>';
  IF array_length(v_rows, 1) IS NULL THEN
    v_body := v_body || pgv.empty('Aucune ligne');
  ELSE
    v_body := v_body || pgv.md_table(
      ARRAY['Description', 'Qté', 'PU', 'TVA', 'Total HT', 'Restant', ''],
      v_rows);
    v_body := v_body || '<p><strong>Total HT :</strong> ' || to_char(purchase._total_ht(p_id), 'FM999 990.00') || ' EUR'
      || ' | <strong>TVA :</strong> ' || to_char(purchase._total_tva(p_id), 'FM999 990.00') || ' EUR'
      || ' | <strong>TTC :</strong> ' || to_char(purchase._total_ttc(p_id), 'FM999 990.00') || ' EUR</p>';
  END IF;

  -- Formulaire ajout ligne (brouillon)
  IF v_cmd.statut = 'brouillon' THEN
    v_body := v_body || '<details><summary>Ajouter une ligne</summary>'
      || '<form data-rpc="post_ligne_ajouter">'
      || format('<input type="hidden" name="p_commande_id" value="%s">', p_id)
      || '<label>Description<input type="text" name="p_description" required></label>'
      || '<div class="pgv-grid">'
      || '<label>Quantité<input type="number" name="p_quantite" value="1" step="0.01" min="0.01"></label>'
      || '<label>Unité<select name="p_unite"><option value="u">u</option><option value="h">h</option><option value="m">m</option><option value="m2">m²</option><option value="m3">m³</option><option value="kg">kg</option><option value="forfait">forfait</option></select></label>'
      || '<label>Prix unitaire<input type="number" name="p_prix_unitaire" step="0.01" min="0" required></label>'
      || '<label>TVA %<select name="p_tva_rate"><option value="20.00" selected>20%</option><option value="10.00">10%</option><option value="5.50">5.5%</option><option value="0.00">0%</option></select></label>'
      || '</div>'
      || '<button type="submit">Ajouter</button>'
      || '</form></details>';
  END IF;

  -- Réceptions
  v_rows_r := ARRAY[]::text[];
  FOR r IN
    SELECT rc.id, rc.numero, rc.received_at, rc.notes,
           (SELECT count(*) FROM purchase.reception_ligne rl WHERE rl.reception_id = rc.id) AS nb_lignes
      FROM purchase.reception rc
     WHERE rc.commande_id = p_id
     ORDER BY rc.received_at DESC
  LOOP
    v_rows_r := v_rows_r || ARRAY[
      pgv.esc(r.numero),
      to_char(r.received_at, 'DD/MM/YYYY HH24:MI'),
      r.nb_lignes::text || ' lignes',
      coalesce(pgv.esc(r.notes), '')
    ];
  END LOOP;

  IF array_length(v_rows_r, 1) IS NOT NULL THEN
    v_body := v_body || '<h4>Réceptions</h4>'
      || pgv.md_table(ARRAY['Numéro', 'Date', 'Lignes', 'Notes'], v_rows_r);
  END IF;

  -- Actions
  v_body := v_body || '<p>';
  IF v_cmd.statut = 'brouillon' THEN
    v_body := v_body
      || format('<a href="%s" role="button">Modifier</a> ', pgv.call_ref('get_commande_form', jsonb_build_object('p_id', p_id)))
      || pgv.action('post_commande_envoyer', 'Envoyer',
           jsonb_build_object('p_id', p_id),
           'Marquer cette commande comme envoyée ?') || ' '
      || pgv.action('post_commande_annuler', 'Annuler',
           jsonb_build_object('p_id', p_id),
           'Annuler cette commande ?', 'danger');
  ELSIF v_cmd.statut IN ('envoyee', 'partiellement_recue') THEN
    v_body := v_body
      || pgv.action('post_reception_creer', 'Réceptionner',
           jsonb_build_object('p_commande_id', p_id),
           'Créer une réception pour cette commande ?') || ' '
      || pgv.action('post_commande_annuler', 'Annuler',
           jsonb_build_object('p_id', p_id),
           'Annuler cette commande ?', 'danger');
  END IF;
  v_body := v_body || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_commande(integer) IS 'Purchase order detail with lines, receptions, and actions by status';

CREATE OR REPLACE FUNCTION purchase.get_commande_form(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd purchase.commande;
  v_title text;
  v_body text;
BEGIN
  IF p_id IS NOT NULL THEN
    SELECT * INTO v_cmd FROM purchase.commande WHERE id = p_id;
    v_title := 'Modifier commande ' || v_cmd.numero;
  ELSE
    v_title := 'Nouvelle commande';
  END IF;

  v_body := '<h3>' || pgv.esc(v_title) || '</h3>'
    || '<form data-rpc="post_commande_save">';

  IF p_id IS NOT NULL THEN
    v_body := v_body || format('<input type="hidden" name="p_id" value="%s">', p_id);
  END IF;

  v_body := v_body
    || '<label>Fournisseur<select name="p_fournisseur_id" required>'
    || purchase._fournisseur_options()
    || '</select></label>';

  -- Pre-select if editing
  IF p_id IS NOT NULL THEN
    v_body := replace(v_body,
      format('value="%s">', v_cmd.fournisseur_id),
      format('value="%s" selected>', v_cmd.fournisseur_id));
  END IF;

  v_body := v_body
    || format('<label>Objet<input type="text" name="p_objet" value="%s" required></label>',
       coalesce(pgv.esc(v_cmd.objet), ''))
    || format('<label>Date livraison prévue<input type="date" name="p_date_livraison" value="%s"></label>',
       coalesce(v_cmd.date_livraison::text, ''))
    || format('<label>Notes<textarea name="p_notes">%s</textarea></label>',
       coalesce(pgv.esc(v_cmd.notes), ''))
    || '<button type="submit">Enregistrer</button>'
    || '</form>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_commande_form(integer) IS 'Form to create or edit a purchase order';

CREATE OR REPLACE FUNCTION purchase.get_facture_fournisseur(p_id integer DEFAULT NULL::integer)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_fac purchase.facture_fournisseur;
  v_cmd_numero text;
  v_fournisseur_id int;
  v_fournisseur_name text;
  v_body text;
  v_rows text[];
  r record;
BEGIN
  -- Liste si pas d'id
  IF p_id IS NULL THEN
    v_rows := ARRAY[]::text[];
    FOR r IN
      SELECT f.id, f.numero_fournisseur, c.numero AS cmd_numero,
             cl.id AS fournisseur_id, cl.name AS fournisseur,
             f.montant_ttc, f.statut, f.date_facture, f.date_echeance
        FROM purchase.facture_fournisseur f
        LEFT JOIN purchase.commande c ON c.id = f.commande_id
        LEFT JOIN crm.client cl ON cl.id = c.fournisseur_id
       ORDER BY f.created_at DESC
    LOOP
      v_rows := v_rows || ARRAY[
        format('<a href="%s">%s</a>', pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero_fournisseur)),
        coalesce(format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)), '—'),
        coalesce(r.cmd_numero, '—'),
        purchase._statut_badge(r.statut),
        to_char(r.montant_ttc, 'FM999 990.00') || ' EUR',
        to_char(r.date_facture, 'DD/MM/YYYY'),
        coalesce(to_char(r.date_echeance, 'DD/MM/YYYY'), '—')
      ];
    END LOOP;

    IF array_length(v_rows, 1) IS NULL THEN
      RETURN pgv.empty('Aucune facture fournisseur', 'Les factures apparaissent ici après saisie.');
    END IF;

    RETURN pgv.md_table(ARRAY['N° fournisseur', 'Fournisseur', 'Commande', 'Statut', 'Montant TTC', 'Date facture', 'Echéance'], v_rows);
  END IF;

  -- Détail
  SELECT * INTO v_fac FROM purchase.facture_fournisseur WHERE id = p_id;
  SELECT numero INTO v_cmd_numero FROM purchase.commande WHERE id = v_fac.commande_id;

  -- Fournisseur via commande
  SELECT c.fournisseur_id, cl.name INTO v_fournisseur_id, v_fournisseur_name
    FROM purchase.commande c
    JOIN crm.client cl ON cl.id = c.fournisseur_id
   WHERE c.id = v_fac.commande_id;

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.card('Facture', pgv.esc(v_fac.numero_fournisseur) || '<br>' || purchase._statut_badge(v_fac.statut)),
    pgv.card('Fournisseur', CASE WHEN v_fournisseur_id IS NOT NULL
      THEN format('<a href="/crm/client?p_id=%s">%s</a>', v_fournisseur_id, pgv.esc(v_fournisseur_name))
      ELSE '—' END),
    pgv.card('Commande', coalesce(v_cmd_numero, '—')),
    pgv.card('Montant HT', to_char(v_fac.montant_ht, 'FM999 990.00') || ' EUR'),
    pgv.card('Montant TTC', to_char(v_fac.montant_ttc, 'FM999 990.00') || ' EUR')
  ]);

  v_body := v_body || '<p>'
    || '<strong>Date facture :</strong> ' || to_char(v_fac.date_facture, 'DD/MM/YYYY')
    || ' | <strong>Echéance :</strong> ' || coalesce(to_char(v_fac.date_echeance, 'DD/MM/YYYY'), '—')
    || '</p>';

  IF v_fac.notes <> '' THEN
    v_body := v_body || '<p><strong>Notes :</strong> ' || pgv.esc(v_fac.notes) || '</p>';
  END IF;

  -- Rapprochement: comparer montants commande vs facture
  IF v_fac.commande_id IS NOT NULL THEN
    DECLARE
      v_cmd_ttc numeric;
      v_ecart numeric;
    BEGIN
      v_cmd_ttc := purchase._total_ttc(v_fac.commande_id);
      v_ecart := v_fac.montant_ttc - v_cmd_ttc;
      v_body := v_body || '<p><strong>Rapprochement :</strong> Commande TTC = '
        || to_char(v_cmd_ttc, 'FM999 990.00') || ' EUR'
        || ' | Ecart = ' || to_char(v_ecart, 'FM999 990.00') || ' EUR';
      IF abs(v_ecart) > 0.01 THEN
        v_body := v_body || ' ' || pgv.badge('écart', 'warning');
      ELSE
        v_body := v_body || ' ' || pgv.badge('OK', 'success');
      END IF;
      v_body := v_body || '</p>';
    END;
  END IF;

  -- Actions
  v_body := v_body || '<p>';
  IF v_fac.statut = 'recue' THEN
    v_body := v_body || pgv.action('post_facture_valider', 'Valider',
      jsonb_build_object('p_id', p_id),
      'Valider cette facture ?');
  ELSIF v_fac.statut = 'validee' THEN
    v_body := v_body || pgv.action('post_facture_payer', 'Marquer payée',
      jsonb_build_object('p_id', p_id),
      'Marquer cette facture comme payée ?');
  END IF;
  v_body := v_body || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_facture_fournisseur(integer) IS 'Supplier invoice list or detail with reconciliation and CRM links';

CREATE OR REPLACE FUNCTION purchase.get_index()
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd_en_cours int;
  v_receptions_attente int;
  v_factures_impayees int;
  v_achats_mois numeric(12,2);
  v_body text;
  v_rows_c text[];
  v_rows_f text[];
  r record;
BEGIN
  -- KPIs
  SELECT count(*)::int INTO v_cmd_en_cours
    FROM purchase.commande WHERE statut IN ('envoyee', 'partiellement_recue');

  SELECT count(DISTINCT c.id)::int INTO v_receptions_attente
    FROM purchase.commande c
    JOIN purchase.ligne l ON l.commande_id = c.id
   WHERE c.statut IN ('envoyee', 'partiellement_recue')
     AND purchase._quantite_restante(l.id) > 0;

  SELECT count(*)::int INTO v_factures_impayees
    FROM purchase.facture_fournisseur WHERE statut IN ('recue', 'validee');

  SELECT coalesce(sum(montant_ttc), 0) INTO v_achats_mois
    FROM purchase.facture_fournisseur
   WHERE statut = 'payee'
     AND created_at >= date_trunc('month', now());

  v_body := pgv.grid(VARIADIC ARRAY[
    pgv.stat('Commandes en cours', v_cmd_en_cours::text),
    pgv.stat('A réceptionner', v_receptions_attente::text),
    pgv.stat('Factures impayées', v_factures_impayees::text),
    pgv.stat('Achats du mois', to_char(v_achats_mois, 'FM999 990.00') || ' EUR')
  ]);

  -- Tab: Commandes récentes
  v_rows_c := ARRAY[]::text[];
  FOR r IN
    SELECT c.id, c.fournisseur_id, c.numero, cl.name AS fournisseur, c.objet, c.statut,
           purchase._total_ttc(c.id) AS ttc, c.created_at
      FROM purchase.commande c
      JOIN crm.client cl ON cl.id = c.fournisseur_id
     ORDER BY c.created_at DESC LIMIT 10
  LOOP
    v_rows_c := v_rows_c || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_commande', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero)),
      format('<a href="/crm/client?p_id=%s">%s</a>', r.fournisseur_id, pgv.esc(r.fournisseur)),
      pgv.esc(r.objet),
      purchase._statut_badge(r.statut),
      to_char(r.ttc, 'FM999 990.00') || ' EUR',
      to_char(r.created_at, 'DD/MM/YYYY')
    ];
  END LOOP;

  -- Tab: Factures récentes
  v_rows_f := ARRAY[]::text[];
  FOR r IN
    SELECT f.id, f.numero_fournisseur, c.numero AS cmd_numero,
           f.montant_ttc, f.statut, f.date_facture, f.date_echeance
      FROM purchase.facture_fournisseur f
      LEFT JOIN purchase.commande c ON c.id = f.commande_id
     ORDER BY f.created_at DESC LIMIT 10
  LOOP
    v_rows_f := v_rows_f || ARRAY[
      format('<a href="%s">%s</a>', pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', r.id)), pgv.esc(r.numero_fournisseur)),
      coalesce(r.cmd_numero, '—'),
      purchase._statut_badge(r.statut),
      to_char(r.montant_ttc, 'FM999 990.00') || ' EUR',
      to_char(r.date_facture, 'DD/MM/YYYY'),
      coalesce(to_char(r.date_echeance, 'DD/MM/YYYY'), '—')
    ];
  END LOOP;

  v_body := v_body || pgv.tabs(VARIADIC ARRAY[
    'Commandes récentes',
    CASE WHEN array_length(v_rows_c, 1) IS NULL
      THEN pgv.empty('Aucune commande', 'Créez votre première commande fournisseur.')
      ELSE pgv.md_table(ARRAY['Numéro', 'Fournisseur', 'Objet', 'Statut', 'Total TTC', 'Date'], v_rows_c)
    END,
    'Factures fournisseur',
    CASE WHEN array_length(v_rows_f, 1) IS NULL
      THEN pgv.empty('Aucune facture fournisseur')
      ELSE pgv.md_table(ARRAY['N° fournisseur', 'Commande', 'Statut', 'Montant TTC', 'Date facture', 'Echéance'], v_rows_f)
    END
  ]);

  v_body := v_body || '<p>'
    || format('<a href="%s" role="button">Nouvelle commande</a>', pgv.call_ref('get_commande_form'))
    || '</p>';

  RETURN v_body;
END;
$function$;
COMMENT ON FUNCTION purchase.get_index() IS 'Dashboard purchase: KPI stats + tabs commandes/factures récentes';

CREATE OR REPLACE FUNCTION purchase.nav_items()
 RETURNS jsonb
 LANGUAGE plpgsql
AS $function$
BEGIN
  RETURN '[{"href":"/","label":"Dashboard","icon":"home"},{"href":"/commande","label":"Commandes","icon":"shopping-cart"},{"href":"/facture_fournisseur","label":"Factures","icon":"receipt"}]'::jsonb;
END;
$function$;
COMMENT ON FUNCTION purchase.nav_items() IS 'Navigation items for purchase module';

CREATE OR REPLACE FUNCTION purchase.post_commande_annuler(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
  v_has_receptions bool;
BEGIN
  SELECT exists(SELECT 1 FROM purchase.reception WHERE commande_id = v_id) INTO v_has_receptions;

  IF v_has_receptions THEN
    RETURN '<template data-toast="error">Impossible d''annuler : des réceptions existent</template>';
  END IF;

  UPDATE purchase.commande SET statut = 'annulee'
   WHERE id = v_id AND statut IN ('brouillon', 'envoyee');

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Commande introuvable ou non annulable</template>';
  END IF;

  RETURN format('<template data-toast="success">Commande annulée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_commande_annuler(jsonb) IS 'Cancel a purchase order (only if no receptions)';

CREATE OR REPLACE FUNCTION purchase.post_commande_envoyer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
BEGIN
  UPDATE purchase.commande SET statut = 'envoyee'
   WHERE id = v_id AND statut = 'brouillon';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Commande introuvable ou déjà envoyée</template>';
  END IF;

  RETURN format('<template data-toast="success">Commande envoyée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_commande_envoyer(jsonb) IS 'Mark purchase order as sent to supplier';

CREATE OR REPLACE FUNCTION purchase.post_commande_save(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
  v_fournisseur_id int := (p_data->>'p_fournisseur_id')::int;
  v_objet text := p_data->>'p_objet';
  v_notes text := coalesce(p_data->>'p_notes', '');
  v_date_livraison date := (p_data->>'p_date_livraison')::date;
BEGIN
  IF v_id IS NOT NULL THEN
    UPDATE purchase.commande
       SET fournisseur_id = v_fournisseur_id,
           objet = v_objet,
           notes = v_notes,
           date_livraison = v_date_livraison
     WHERE id = v_id AND statut = 'brouillon';

    IF NOT FOUND THEN
      RETURN '<template data-toast="error">Commande introuvable ou non modifiable</template>';
    END IF;

    RETURN format('<template data-toast="success">Commande mise à jour</template><template data-redirect="%s"></template>',
      pgv.call_ref('get_commande', jsonb_build_object('p_id', v_id)));
  ELSE
    INSERT INTO purchase.commande (numero, fournisseur_id, objet, notes, date_livraison)
    VALUES (purchase._next_numero('CMD'), v_fournisseur_id, v_objet, v_notes, v_date_livraison)
    RETURNING id INTO v_id;

    RETURN format('<template data-toast="success">Commande créée</template><template data-redirect="%s"></template>',
      pgv.call_ref('get_commande', jsonb_build_object('p_id', v_id)));
  END IF;
END;
$function$;
COMMENT ON FUNCTION purchase.post_commande_save(jsonb) IS 'Create or update a purchase order (draft only)';

CREATE OR REPLACE FUNCTION purchase.post_facture_payer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
BEGIN
  UPDATE purchase.facture_fournisseur SET statut = 'payee'
   WHERE id = v_id AND statut = 'validee';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Facture introuvable ou non validée</template>';
  END IF;

  RETURN format('<template data-toast="success">Facture marquée payée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_facture_payer(jsonb) IS 'Mark a supplier invoice as paid';

CREATE OR REPLACE FUNCTION purchase.post_facture_saisir(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
BEGIN
  INSERT INTO purchase.facture_fournisseur (
    commande_id, numero_fournisseur, montant_ht, montant_ttc,
    date_facture, date_echeance, notes
  ) VALUES (
    (p_data->>'p_commande_id')::int,
    p_data->>'p_numero_fournisseur',
    (p_data->>'p_montant_ht')::numeric,
    (p_data->>'p_montant_ttc')::numeric,
    (p_data->>'p_date_facture')::date,
    (p_data->>'p_date_echeance')::date,
    coalesce(p_data->>'p_notes', '')
  ) RETURNING id INTO v_id;

  RETURN format('<template data-toast="success">Facture fournisseur saisie</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_facture_saisir(jsonb) IS 'Record a supplier invoice';

CREATE OR REPLACE FUNCTION purchase.post_facture_valider(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int := (p_data->>'p_id')::int;
BEGIN
  UPDATE purchase.facture_fournisseur SET statut = 'validee'
   WHERE id = v_id AND statut = 'recue';

  IF NOT FOUND THEN
    RETURN '<template data-toast="error">Facture introuvable ou déjà validée</template>';
  END IF;

  RETURN format('<template data-toast="success">Facture validée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_facture_fournisseur', jsonb_build_object('p_id', v_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_facture_valider(jsonb) IS 'Validate a supplier invoice';

CREATE OR REPLACE FUNCTION purchase.post_ligne_ajouter(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_commande_id int := (p_data->>'p_commande_id')::int;
  v_statut text;
  v_sort int;
BEGIN
  SELECT statut INTO v_statut FROM purchase.commande WHERE id = v_commande_id;
  IF v_statut IS NULL OR v_statut <> 'brouillon' THEN
    RETURN '<template data-toast="error">Lignes modifiables uniquement sur brouillon</template>';
  END IF;

  SELECT coalesce(max(sort_order), 0) + 1 INTO v_sort
    FROM purchase.ligne WHERE commande_id = v_commande_id;

  INSERT INTO purchase.ligne (commande_id, sort_order, description, quantite, unite, prix_unitaire, tva_rate)
  VALUES (
    v_commande_id,
    v_sort,
    p_data->>'p_description',
    coalesce((p_data->>'p_quantite')::numeric, 1),
    coalesce(p_data->>'p_unite', 'u'),
    (p_data->>'p_prix_unitaire')::numeric,
    coalesce((p_data->>'p_tva_rate')::numeric, 20.00)
  );

  RETURN format('<template data-toast="success">Ligne ajoutée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_commande_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_ligne_ajouter(jsonb) IS 'Add a line to a draft purchase order';

CREATE OR REPLACE FUNCTION purchase.post_ligne_supprimer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_ligne_id int := (p_data->>'p_ligne_id')::int;
  v_commande_id int;
  v_statut text;
BEGIN
  SELECT l.commande_id, c.statut INTO v_commande_id, v_statut
    FROM purchase.ligne l
    JOIN purchase.commande c ON c.id = l.commande_id
   WHERE l.id = v_ligne_id;

  IF v_statut IS NULL OR v_statut <> 'brouillon' THEN
    RETURN '<template data-toast="error">Lignes modifiables uniquement sur brouillon</template>';
  END IF;

  DELETE FROM purchase.ligne WHERE id = v_ligne_id;

  RETURN format('<template data-toast="success">Ligne supprimée</template><template data-redirect="%s"></template>',
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_commande_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_ligne_supprimer(jsonb) IS 'Remove a line from a draft purchase order';

CREATE OR REPLACE FUNCTION purchase.post_reception_creer(p_data jsonb)
 RETURNS text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_commande_id int := (p_data->>'p_commande_id')::int;
  v_statut text;
  v_reception_id int;
  v_numero text;
  v_nb_lignes int := 0;
  v_all_received bool;
  r record;
BEGIN
  SELECT statut INTO v_statut FROM purchase.commande WHERE id = v_commande_id;
  IF v_statut NOT IN ('envoyee', 'partiellement_recue') THEN
    RETURN '<template data-toast="error">Commande non réceptionnable</template>';
  END IF;

  v_numero := purchase._next_numero('REC');
  INSERT INTO purchase.reception (commande_id, numero, notes)
  VALUES (v_commande_id, v_numero, coalesce(p_data->>'p_notes', ''))
  RETURNING id INTO v_reception_id;

  -- Réceptionner toutes les quantités restantes
  FOR r IN
    SELECT l.id AS ligne_id, purchase._quantite_restante(l.id) AS restante
      FROM purchase.ligne l
     WHERE l.commande_id = v_commande_id
       AND purchase._quantite_restante(l.id) > 0
  LOOP
    INSERT INTO purchase.reception_ligne (reception_id, ligne_id, quantite_recue)
    VALUES (v_reception_id, r.ligne_id, r.restante);
    v_nb_lignes := v_nb_lignes + 1;
  END LOOP;

  IF v_nb_lignes = 0 THEN
    -- Rien à réceptionner, rollback reception
    DELETE FROM purchase.reception WHERE id = v_reception_id;
    RETURN '<template data-toast="error">Tout est déjà réceptionné</template>';
  END IF;

  -- Vérifier si tout est reçu
  SELECT NOT exists(
    SELECT 1 FROM purchase.ligne l
     WHERE l.commande_id = v_commande_id
       AND purchase._quantite_restante(l.id) > 0
  ) INTO v_all_received;

  IF v_all_received THEN
    UPDATE purchase.commande SET statut = 'recue' WHERE id = v_commande_id;
  ELSE
    UPDATE purchase.commande SET statut = 'partiellement_recue' WHERE id = v_commande_id;
  END IF;

  -- TODO: créer mouvements stock quand module stock implémenté

  RETURN format('<template data-toast="success">Réception %s créée (%s lignes)</template><template data-redirect="%s"></template>',
    v_numero, v_nb_lignes,
    pgv.call_ref('get_commande', jsonb_build_object('p_id', v_commande_id)));
END;
$function$;
COMMENT ON FUNCTION purchase.post_reception_creer(jsonb) IS 'Create a reception for all remaining quantities of a purchase order';

GRANT USAGE ON SCHEMA purchase TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA purchase TO web_anon;

-- Schema: purchase_ut
CREATE SCHEMA IF NOT EXISTS purchase_ut;

CREATE OR REPLACE FUNCTION purchase_ut.test_commande_workflow()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_result text;
  v_fournisseur_id int;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  -- Setup: create a supplier
  INSERT INTO crm.client (type, name, tags)
  VALUES ('company', '_test_fournisseur_', ARRAY['fournisseur'])
  RETURNING id INTO v_fournisseur_id;

  -- Create order
  v_result := purchase.post_commande_save(jsonb_build_object(
    'p_fournisseur_id', v_fournisseur_id,
    'p_objet', 'Test commande workflow'
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'create order returns success');

  SELECT id INTO v_id FROM purchase.commande WHERE objet = 'Test commande workflow';
  RETURN NEXT ok(v_id IS NOT NULL, 'order created');

  -- Add lines
  v_result := purchase.post_ligne_ajouter(jsonb_build_object(
    'p_commande_id', v_id,
    'p_description', 'Test article',
    'p_quantite', 5,
    'p_prix_unitaire', 10.00
  ));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'add line returns success');

  -- Send
  v_result := purchase.post_commande_envoyer(jsonb_build_object('p_id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'send returns success');
  RETURN NEXT is((SELECT statut FROM purchase.commande WHERE id = v_id), 'envoyee', 'status is envoyee');

  -- Receive
  v_result := purchase.post_reception_creer(jsonb_build_object('p_commande_id', v_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'reception returns success');
  RETURN NEXT is((SELECT statut FROM purchase.commande WHERE id = v_id), 'recue', 'status is recue after full reception');

  -- Cleanup
  DELETE FROM purchase.reception_ligne WHERE reception_id IN (SELECT id FROM purchase.reception WHERE commande_id = v_id);
  DELETE FROM purchase.reception WHERE commande_id = v_id;
  DELETE FROM purchase.ligne WHERE commande_id = v_id;
  DELETE FROM purchase.commande WHERE id = v_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_commande_workflow() IS 'Test full purchase order workflow: create, send, receive';

CREATE OR REPLACE FUNCTION purchase_ut.test_pages_render()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  RETURN NEXT ok(length(purchase.brand()) > 0, 'brand() returns text');
  RETURN NEXT ok(purchase.nav_items() IS NOT NULL, 'nav_items() returns jsonb');
  RETURN NEXT ok(length(purchase.get_index()) > 0, 'get_index() returns HTML');
  RETURN NEXT ok(length(purchase.get_commande()) > 0, 'get_commande() list returns HTML');
  RETURN NEXT ok(length(purchase.get_commande_form()) > 0, 'get_commande_form() returns HTML');
  RETURN NEXT ok(length(purchase.get_facture_fournisseur()) > 0, 'get_facture_fournisseur() list returns HTML');
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_pages_render() IS 'Test all pages render without error';

CREATE OR REPLACE FUNCTION purchase_ut.test_reception_partielle()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_cmd_id int;
  v_fournisseur_id int;
  v_result text;
  v_remaining numeric;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  INSERT INTO crm.client (type, name, tags)
  VALUES ('company', '_test_partial_', ARRAY['fournisseur'])
  RETURNING id INTO v_fournisseur_id;

  -- Create and send order with 10 items
  v_result := purchase.post_commande_save(jsonb_build_object(
    'p_fournisseur_id', v_fournisseur_id,
    'p_objet', 'Test reception partielle'
  ));
  SELECT id INTO v_cmd_id FROM purchase.commande WHERE objet = 'Test reception partielle';

  v_result := purchase.post_ligne_ajouter(jsonb_build_object(
    'p_commande_id', v_cmd_id,
    'p_description', 'Planches test',
    'p_quantite', 10,
    'p_prix_unitaire', 25.00
  ));

  v_result := purchase.post_commande_envoyer(jsonb_build_object('p_id', v_cmd_id));
  RETURN NEXT is((SELECT statut FROM purchase.commande WHERE id = v_cmd_id), 'envoyee', 'order is envoyee');

  -- Full reception via post_reception_creer (receives all remaining)
  v_result := purchase.post_reception_creer(jsonb_build_object('p_commande_id', v_cmd_id));
  RETURN NEXT ok(v_result LIKE '%data-toast="success"%', 'reception created');
  RETURN NEXT is((SELECT statut FROM purchase.commande WHERE id = v_cmd_id), 'recue', 'status becomes recue');

  -- Check remaining via SQL
  SELECT l.quantite - coalesce(sum(rl.quantite_recue), 0) INTO v_remaining
    FROM purchase.ligne l
    LEFT JOIN purchase.reception_ligne rl ON rl.ligne_id = l.id
   WHERE l.commande_id = v_cmd_id
   GROUP BY l.id;

  RETURN NEXT is(v_remaining, 0.00::numeric, 'no remaining quantity');

  -- Second reception should fail (nothing left)
  v_result := purchase.post_reception_creer(jsonb_build_object('p_commande_id', v_cmd_id));
  RETURN NEXT ok(v_result LIKE '%Commande non réceptionnable%', 'cannot receive already received');

  -- Cleanup
  DELETE FROM purchase.reception_ligne WHERE reception_id IN (SELECT id FROM purchase.reception WHERE commande_id = v_cmd_id);
  DELETE FROM purchase.reception WHERE commande_id = v_cmd_id;
  DELETE FROM purchase.ligne WHERE commande_id = v_cmd_id;
  DELETE FROM purchase.commande WHERE id = v_cmd_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_reception_partielle() IS 'Test reception workflow and remaining quantity tracking';

CREATE OR REPLACE FUNCTION purchase_ut.test_totaux()
 RETURNS SETOF text
 LANGUAGE plpgsql
AS $function$
DECLARE
  v_id int;
  v_fournisseur_id int;
  v_ht numeric;
  v_ttc numeric;
BEGIN
  PERFORM set_config('app.tenant_id', 'dev', true);

  INSERT INTO crm.client (type, name, tags)
  VALUES ('company', '_test_totaux_', ARRAY['fournisseur'])
  RETURNING id INTO v_fournisseur_id;

  INSERT INTO purchase.commande (numero, fournisseur_id, objet)
  VALUES ('CMD-TEST-TOT', v_fournisseur_id, 'Test totaux')
  RETURNING id INTO v_id;

  -- 2 x 100.00 @ 20% TVA = 200 HT, 40 TVA, 240 TTC
  INSERT INTO purchase.ligne (commande_id, sort_order, description, quantite, prix_unitaire, tva_rate)
  VALUES (v_id, 1, 'Article A', 2, 100.00, 20.00);

  -- 1 x 50.00 @ 10% TVA = 50 HT, 5 TVA, 55 TTC
  INSERT INTO purchase.ligne (commande_id, sort_order, description, quantite, prix_unitaire, tva_rate)
  VALUES (v_id, 2, 'Article B', 1, 50.00, 10.00);

  -- Test via get_commande (which uses _total_* internally)
  SELECT sum(quantite * prix_unitaire) INTO v_ht FROM purchase.ligne WHERE commande_id = v_id;
  RETURN NEXT is(v_ht, 250.00::numeric, 'total HT = 250');

  SELECT sum(quantite * prix_unitaire * (1 + tva_rate/100)) INTO v_ttc FROM purchase.ligne WHERE commande_id = v_id;
  RETURN NEXT is(v_ttc, 295.00::numeric, 'total TTC = 295');

  -- Verify page renders with totals
  RETURN NEXT ok(purchase.get_commande(v_id) LIKE '%295%', 'detail page shows TTC total');

  -- Cleanup
  DELETE FROM purchase.ligne WHERE commande_id = v_id;
  DELETE FROM purchase.commande WHERE id = v_id;
  DELETE FROM crm.client WHERE id = v_fournisseur_id;
END;
$function$;
COMMENT ON FUNCTION purchase_ut.test_totaux() IS 'Test HT/TVA/TTC calculations';

GRANT USAGE ON SCHEMA purchase_ut TO web_anon;
GRANT EXECUTE ON ALL FUNCTIONS IN SCHEMA purchase_ut TO web_anon;

